&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;gt;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;greater-then&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#62;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;大于号（右尖括号）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;(&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;left parenthesis&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#40;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;左圆括号&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;)&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;right parenthesis&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#41;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;右圆括号&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;[&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;left square bracket&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#91;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;左方括号&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;]&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;right square bracket&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#93;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;右方括号&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;{&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;left curly brace&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#123;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;左大括号&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;}&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;right curly brace&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#125;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;右大括号&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;/&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;slash&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#47;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;左斜杠&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;|&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;vertical bar&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#124;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;竖线&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;\&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;backslash&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#92;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;右斜杠&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;~&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;tilde&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#126;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;波浪号&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;_&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;underscore&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#95;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;下划线&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;+&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;plus sign&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#43;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;加号&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;-&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;hyphen&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#45;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;减号（连字符）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;,&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;comma&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#44;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;逗号&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;.&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;period&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#46;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;句号&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;0-9&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;number&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#48; - &amp;amp;#57;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;数字0-9&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;a-z&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;lowercase&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#97; - &amp;amp;#122;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;小写字母a-z&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;A-Z&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;uppercase&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;amp;#65; - &amp;amp;#90;&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;大写字母A-Z&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
